    $len1 = strlen($normalized1);
    $len2 = strlen($normalized2);
    $matrix = array();

    for ($i = 0; $i <= $len1; $i++) {
        $matrix[$i] = array_fill(0, $len2 + 1, 0);
    }

    for ($i = 0; $i <= $len1; $i++) {
        $matrix[$i][0] = $i;
    }

    for ($j = 0; $j <= $len2; $j++) {
        $matrix[0][$j] = $j;
    }

    for ($i = 1; $i <= $len1; $i++) {
        for ($j = 1; $j <= $len2; $j++) {
            $cost = ($normalized1[$i - 1] == $normalized2[$j - 1]) ? 0 : 1;
            $matrix[$i][$j] = min(
                $matrix[$i - 1][$j] + 1,
                $matrix[$i][$j - 1] + 1,
                $matrix[$i - 1][$j - 1] + $cost
            );
        }
    }

    $max_len = max($len1, $len2);
    $similarity = 1 - ($matrix[$len1][$len2] / $max_len);

    return $similarity;
}

