    public function edit($request, $response, $args)
    {
		$themes=Tools::getDir(BASE_PATH."/resources/views");
		     $id = $request->getParam('id');
        if (!$id) {
            $response->getBody()->write(json_encode(['ret' => 0, 'msg' => 'Invalid request']));
            return $response;
        }

        $ann = Ann::find($id);
        if (!$ann) {
            $response->getBody()->write(json_encode(['ret' => 0, 'msg' => 'Announcement not found']));
            return $response;
        }

        if ($request->getParam('method') == 'update') {
            $ann->title = $request->getParam('title');
            $ann->content = $request->getParam('content');
            $ann->save();

            $response->getBody()->write(json_encode(['ret' => 1, 'msg' => 'Update successful']));
            return $response;
        }

        return $this->view()->assign("ann", $ann)->assign("themes", $themes)->display('admin/announcement/edit.tpl');
    }

