    public function edit($request, $response, $args)
    {
        $categories = Tools::getCategories(BASE_PATH . '/resources/tasks/categories');
        $id = $request->getParam('id');
        if (!$id) {
            $response->getBody()->write(json_encode(['ret' => 0, 'msg' => 'Invalid request']));
            return $response;
        }

        $task = Task::find($id);
        if (!$task) {
            $response->getBody()->write(json_encode(['ret' => 0, 'msg' => 'Task not found']));
            return $response;
        }

        if ($request->getParam('method') == 'update') {
            $task->title = $request->getParam('title');
            $task->description = $request->getParam('description');
            $task->category = $request->getParam('category');
            $task->save();

            $response->getBody()->write(json_encode(['ret' => 1, 'msg' => 'Update successful']));
            return $response;
        }

        return $this->view()->assign('task', $task)->assign('categories', $categories)->display('user/tasks/edit.tpl');
    }

