        cmd = ["pylint", "--output-format=colorized", module]

        try:
            # Run pylint and capture output
            process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            stdout, stderr = process.communicate()

            # Display results with appropriate colors
            for line in stdout.splitlines():
                if any(prefix in line for prefix in colors):
                    prefix = next((p for p in colors if p in line), None)
                    self.results.insert(END, line, prefix)
                else:
                    self.results.insert(END, line)

            if stderr:
                self.results.insert(END, "\nErrors during linting:")
                for line in stderr.splitlines():
                    self.results.insert(END, line, '**')

        except Exception as e:
            self.results.insert(END, f"Failed to run pylint: {str(e)}")
