  async compileStylusFiles() {
    const
      { source, viewerDest } = this,
      onEnd = this.onEnd('viewer styles compiled successfully.'),
      stylusFiles = glob.sync(`${source}/styles/**/[!_]*.styl`);

    // Process each Stylus file and combine into a single CSS output
    let combinedCSS = '';
    for (const file of stylusFiles) {
      const content = await fs.readFile(file, 'utf8');
      combinedCSS += await stylus.render(content, { filename: file });
    }

    // Apply post-processing for vendor prefixes and minification
    const processedCSS = await postcss([autoprefixer, cssnano]).process(combinedCSS, {
      from: undefined
    });

    return processedCSS.css;
  }

